const bodyRaw = $json.body || '';
let body = '';
if (typeof bodyRaw === 'string') {
  body = bodyRaw;
} else if (bodyRaw && bodyRaw.content) {
  body = String(bodyRaw.content);
} else if (bodyRaw) {
  body = JSON.stringify(bodyRaw);
}

const plainUrlPattern = /https?:\/\/[^\s<>"']+/gi;
const matches = body.match(plainUrlPattern);
const allUrls = matches ? matches : [];

const objectReturned = {json: {
    messageId : $json.id,
    links: allUrls
  }
}

return objectReturned

