// Parse and validate Gemini response
 const item = $input.item;

 // Check for errors
 if (item.json.error) {
   return {
     json: {
       isValid: false,
       validationError: 'Gemini extraction failed',
       messageId: item.json.messageId
     }
   };
 }

 // Get the text response from the correct path and clean markdown
 let response = item.json.content?.parts?.[0]?.text || item.json.text || '';
 response = response.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();

 try {
   const data = JSON.parse(response);

   const isValid =
     (data.customer_tax_id === null || data.customer_tax_id?.length >= 10) &&
     data.customer_company?.length > 0 &&
     data.invoice_issued_date?.match(/\d{4}-\d{2}-\d{2}/) &&
     data.invoice_number?.length > 0 &&
     data.invoice_amount_gross !== undefined &&
     data.currency?.length >= 3 &&
     data.category?.length > 0;

   return {
     json: {
       ...data,
       isValid: isValid,
       validationError: isValid ? null : 'Missing or invalid required fields',
       messageId: item.json.messageId
     },
     binary: $('Analyze document').item.binary
   };

 } catch (e) {
   return {
     json: {
       isValid: false,
       validationError: 'JSON parse failed: ' + e.message,
       rawResponse: response.substring(0, 200),
       messageId: item.json.messageId
     }
   };
 }

const allItems = $('Invoice Data Valid?').all();
 const folders = $('Get Months Folders JDG').all();
 const results = [];

 for (const item of allItems) {
   const invoiceData = item.json;
   const invoiceMonth = invoiceData['invoice_issued_month-pl'];
   const matchingFolder = folders.find(folder => folder.json.name === invoiceMonth);

   if (matchingFolder) {
     const dateCompact = (invoiceData.invoice_issued_date || '').replace(/-/g, '');
     const category = (invoiceData.category || 'unknown').toLowerCase();
     const fileName = `${dateCompact}-${category}.pdf`;

     const storeFileItem = $('StoreFile').all()[results.length];
     const renamedBinary = {
       currentFile: {
         ...storeFileItem.binary.currentFile,
         fileName: fileName
       }
     };

     results.push({
       json: {
         folderId: matchingFolder.json.id,
         folderName: matchingFolder.json.name,
         folderPath: matchingFolder.json.webUrl,
         fileName: fileName,
         messageID: storeFileItem.json.messageID,
         supplier_company: invoiceData.supplier_company,
         customer_tax_id: invoiceData.customer_tax_id,
         customer_company: invoiceData.customer_company,
         invoice_number: invoiceData.invoice_number,
         invoice_issued_date: invoiceData.invoice_issued_date,
         invoice_amount_net: invoiceData.invoice_amount_net,
         invoice_amount_tax: invoiceData.invoice_amount_tax,
         invoice_amount_gross: invoiceData.invoice_amount_gross,
         currency: invoiceData.currency,
         category: invoiceData.category
       },
       binary: renamedBinary
     });
   }
 }

 return results;

